module RefModule(
  input clk,
  input rst,
  output reg VPWR,
  output reg VGND,
  output reg VPB,
  output reg VNB
);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk, posedge rst or posedge dbg_halt) begin
    if (rst) begin
      VPWR <= 0;
      VGND <= 0;
      VPB <= 0;
      VNB <= 0;
    end else begin
      VPWR <= 1;
      VGND <= 0;
      VPB <= 1;
      VNB <= 0;
    end
  end
endmodule
